phase1.code:
#include <iostream>
#include <map>
#include <string>
#include <vector>

struct ItemData {
    std::string name;
    int value;
    int weight;
    std::string type;
};

int main() {
    std::cout << "=== std::map — Item Databases & Lookup Tables ===" << std::endl;

    // 1. Creating a map (key-value pairs, sorted by key)
    std::cout << "\n--- Creating maps ---" << std::endl;
    std::map<int, std::string> players = {
        {1, "Hero"},
        {2, "Aragorn"},
        {3, "Gandalf"}
    };

    std::map<std::string, int> scores = {
        {"Hero", 100},
        {"Aragorn", 85},
        {"Gandalf", 95}
    };

    // 2. Accessing elements
    std::cout << "\n--- Accessing elements ---" << std::endl;
    std::cout << "Player 1: " << players[1] << std::endl;
    std::cout << "Hero's score: " << scores["Hero"] << std::endl;

    // 3. Iterating over map
    std::cout << "\n--- Iterating over map ---" << std::endl;
    for (const auto& pair : players) {
        std::cout << "ID " << pair.first << ": " << pair.second << std::endl;
    }

    // 4. Adding and updating elements
    std::cout << "\n--- Adding and updating ---" << std::endl;
    players[4] = "Legolas";  // Add new
    scores["Hero"] = 120;    // Update existing

    for (const auto& pair : scores) {
        std::cout << pair.first << ": " << pair.second << std::endl;
    }

    // 5. Checking if key exists
    std::cout << "\n--- Checking existence ---" << std::endl;
    if (scores.find("Legolas") != scores.end()) {
        std::cout << "Legolas has a score" << std::endl;
    } else {
        std::cout << "Legolas not found" << std::endl;
    }

    // 6. Removing elements
    std::cout << "\n--- Removing elements ---" << std::endl;
    players.erase(2);  // Remove Aragorn
    std::cout << "After erasing ID 2:" << std::endl;
    for (const auto& pair : players) {
        std::cout << "ID " << pair.first << ": " << pair.second << std::endl;
    }

    // 7. Game use: item database
    std::cout << "\n--- Item Database (map) ---" << std::endl;
    std::map<int, ItemData> itemDB;

    itemDB[101] = {"Iron Sword", 50, 3, "weapon"};
    itemDB[102] = {"Health Potion", 25, 1, "consumable"};
    itemDB[103] = {"Steel Shield", 40, 5, "armor"};
    itemDB[104] = {"Magic Staff", 80, 2, "weapon"};

    // Look up item by ID
    int itemId = 103;
    if (itemDB.find(itemId) != itemDB.end()) {
        const ItemData& item = itemDB[itemId];
        std::cout << "Item " << itemId << ": " << item.name 
                  << " (Value: " << item.value << ", Weight: " << item.weight 
                  << ", Type: " << item.type << ")" << std::endl;
    } else {
        std::cout << "Item " << itemId << " not found" << std::endl;
    }

    // 8. Map properties
    std::cout << "\n--- Map properties ---" << std::endl;
    std::cout << "Size: " << itemDB.size() << std::endl;
    std::cout << "Is empty? " << (itemDB.empty() ? "Yes" : "No") << std::endl;

    std::cout << "\n--- When to use std::map ---" << std::endl;
    std::cout << "✅ Key-value lookup" << std::endl;
    std::cout << "✅ Sorted keys" << std::endl;
    std::cout << "✅ Range queries" << std::endl;

    return 0;
}

phase2.brokenCode:
#include <iostream>
#include <map>

int main() {
    std::map<int, std::string> players;

    // Using [] to access non-existent key (inserts it!)
    std::cout << players[10] << std::endl;  // Inserts key 10!

    std::cout << "Size: " << players.size() << std::endl;  // Now 1!

    return 0;
}

phase2.explanation:
`operator[]` in `std::map` inserts a default value if the key doesn't exist!

**What's happening:**
1. `players[10]` looks for key 10
2. Key doesn't exist → inserts it with default value (empty string)
3. Prints the empty string
4. Size becomes 1

**The fix:**
```cpp
// Use find() to check without inserting
auto it = players.find(10);
if (it != players.end()) {
    std::cout << it->second << std::endl;
} else {
    std::cout << "Key not found" << std::endl;
}
```

**PlusPlus-chan says:**
"`operator[]` is convenient but dangerous. It inserts. Use `find()` when you just want to check."

phase3.solution:
#include <iostream>
#include <map>
#include <string>

int main() {
    std::map<int, std::string> shop = {
        {101, "Health Potion"},
        {102, "Mana Potion"},
        {103, "Iron Sword"},
        {104, "Steel Shield"}
    };

    std::cout << "=== Shop Inventory ===" << std::endl;
    for (const auto& item : shop) {
        std::cout << "ID " << item.first << ": " << item.second << std::endl;
    }

    std::cout << "\nItem 103: " << shop[103] << std::endl;

    if (shop.find(105) != shop.end()) {
        std::cout << "Item 105 found" << std::endl;
    } else {
        std::cout << "Item 105 not found" << std::endl;
    }

    shop[105] = "Magic Staff";
    shop[102] = "Super Mana Potion";
    shop.erase(104);

    std::cout << "\nFinal Shop:" << std::endl;
    for (const auto& item : shop) {
        std::cout << "ID " << item.first << ": " << item.second << std::endl;
    }

    return 0;
}
